import React, { useState } from "react";
import axios from "axios";

function Checkout() {
  const [form, setForm] = useState({ name: "", email: "", phone: "" });
  const [grandTotal, setGrandTotal] = useState(1000); // demo total

  const saveOrder = async (status, paymentId) => {
    try {
      await axios.post("http://localhost:5000/api/orders", {
        name: form.name,
        email: form.email,
        phone: form.phone,
        total: grandTotal,
        status,
        paymentId,
      });
      alert("✅ Order saved successfully!");
    } catch (err) {
      console.error("❌ Order save error:", err);
    }
  };

  const placeOrder = async () => {
    try {
      // 1️⃣ Create Razorpay order from backend
      const { data: order } = await axios.post(
        "http://localhost:5000/api/payment/create-order",
        { amount: grandTotal }
      );

      // 2️⃣ Open Razorpay checkout
      const options = {
        key: "rzp_live_R9v7zIgLdfx7XK", // ✅ Or use process.env.REACT_APP_RAZORPAY_KEY_ID
        amount: order.amount,
        currency: order.currency,
        name: "CREWS Clothing",
        description: "Order Payment",
        order_id: order.id, // ✅ VERY IMPORTANT
        handler: async function (response) {
          // ✅ Save order when payment is successful
          await saveOrder("Paid", response.razorpay_payment_id);
        },
        prefill: {
          name: form.name,
          email: form.email,
          contact: form.phone,
        },
        theme: { color: "#3399cc" },
      };

      const rzp = new window.Razorpay(options);
      rzp.open();
    } catch (err) {
      console.error("❌ Razorpay Checkout Error:", err);
      alert("Payment failed. Try again.");
    }
  };

  return (
    <div>
      <h2>Checkout</h2>
      <input
        type="text"
        placeholder="Name"
        value={form.name}
        onChange={(e) => setForm({ ...form, name: e.target.value })}
      />
      <input
        type="email"
        placeholder="Email"
        value={form.email}
        onChange={(e) => setForm({ ...form, email: e.target.value })}
      />
      <input
        type="text"
        placeholder="Phone"
        value={form.phone}
        onChange={(e) => setForm({ ...form, phone: e.target.value })}
      />

      <h3>Total: ₹{grandTotal}</h3>
      <button onClick={placeOrder}>Pay Online</button>
    </div>
  );
}

export default Checkout;
